values.value:
{
  "type": "object",
  "required": ["Name", "AccountId", "CloseDate", "StageName"],
  "properties": {
    "Name": {
      "type": "string",
      "maxLength": 120,
      "description": "Opportunity name"
    },
    "AccountId": {
      "type": "string",
      "pattern": "^001[a-zA-Z0-9]{15}$",
      "description": "Account ID (18 chars)"
    },
    "Amount": {
      "type": "number",
      "minimum": 0,
      "description": "Opportunity amount"
    },
    "CloseDate": {
      "type": "string",
      "format": "date",
      "description": "Expected close date (YYYY-MM-DD)"
    },
    "StageName": {
      "type": "string",
      "enum": ["Prospecting", "Qualification", "Proposal", "Negotiation"],
      "description": "Sales stage"
    },
    "Description": {
      "type": "string",
      "maxLength": 32000,
      "description": "Opportunity description"
    }
  }
}
